// src/pages/AnalyticsPage.js

import React, { useState, useEffect } from "react";
import AppLayout from "../components/AppLayout";
import {
  AreaChart, Area, BarChart, Bar, LineChart, Line,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  RadialBarChart, RadialBar, Legend,
} from "recharts";

/* ─── Static data ─────────────────────────────────────────── */
const WEEKLY_DATA = [
  { day: "Mon", sessions: 4,  advice: 3,  score: 62 },
  { day: "Tue", sessions: 7,  advice: 5,  score: 65 },
  { day: "Wed", sessions: 5,  advice: 4,  score: 68 },
  { day: "Thu", sessions: 9,  advice: 8,  score: 72 },
  { day: "Fri", sessions: 8,  advice: 6,  score: 75 },
  { day: "Sat", sessions: 5,  advice: 3,  score: 76 },
  { day: "Sun", sessions: 11, advice: 9,  score: 78 },
];

const MONTHLY_DATA = [
  { day: "W1", sessions: 18, advice: 14, score: 55 },
  { day: "W2", sessions: 24, advice: 19, score: 62 },
  { day: "W3", sessions: 31, advice: 25, score: 70 },
  { day: "W4", sessions: 49, advice: 35, score: 78 },
];

const PROGRESS_DATA = [
  { name: "Idea Validation",    value: 85, fill: "#a3e635" },
  { name: "Customer Discovery", value: 60, fill: "#22d3ee" },
  { name: "MVP Development",    value: 40, fill: "#60a5fa" },
  { name: "Fundraising Prep",   value: 20, fill: "#c084fc" },
];

const METRICS = [
  { label: "AI Sessions",    value: "49",  delta: "+11 this week", color: "#a3e635", bg: "rgba(163,230,53,0.08)",  border: "rgba(163,230,53,0.2)"  },
  { label: "Goals Defined",  value: "5",   delta: "2 completed",   color: "#22d3ee", bg: "rgba(34,211,238,0.08)",  border: "rgba(34,211,238,0.2)"  },
  { label: "Profile Score",  value: "78%", delta: "+12% vs last",  color: "#60a5fa", bg: "rgba(96,165,250,0.08)",  border: "rgba(96,165,250,0.2)"  },
  { label: "Advice Actions", value: "35",  delta: "4 in progress", color: "#c084fc", bg: "rgba(192,132,252,0.08)", border: "rgba(192,132,252,0.2)" },
];

/* ─── Custom tooltip ──────────────────────────────────────── */
const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{
      background: "#0f172a",
      border: "1px solid rgba(255,255,255,0.08)",
      borderRadius: 12,
      padding: "10px 14px",
      fontSize: 12,
    }}>
      <p style={{ color: "#94a3b8", marginBottom: 6, fontWeight: 600 }}>{label}</p>
      {payload.map((p) => (
        <p key={p.name} style={{ color: p.color, margin: "2px 0" }}>
          {p.name}: <strong>{p.value}</strong>
        </p>
      ))}
    </div>
  );
};

/* ─── Tab button ──────────────────────────────────────────── */
const Tab = ({ active, onClick, children }) => (
  <button
    onClick={onClick}
    style={{
      padding: "6px 16px",
      borderRadius: 8,
      border: "none",
      fontSize: 12,
      fontWeight: 600,
      cursor: "pointer",
      transition: "all 0.2s",
      background: active ? "rgba(163,230,53,0.15)" : "transparent",
      color: active ? "#a3e635" : "#64748b",
      outline: active ? "1px solid rgba(163,230,53,0.3)" : "1px solid transparent",
    }}
  >
    {children}
  </button>
);

/* ─── Chart selector button ───────────────────────────────── */
const ChartBtn = ({ active, onClick, children }) => (
  <button
    onClick={onClick}
    style={{
      padding: "5px 12px",
      borderRadius: 6,
      border: "1px solid",
      fontSize: 11,
      fontWeight: 600,
      cursor: "pointer",
      transition: "all 0.2s",
      background: active ? "#1e293b" : "transparent",
      color: active ? "#e2e8f0" : "#475569",
      borderColor: active ? "rgba(255,255,255,0.1)" : "transparent",
    }}
  >
    {children}
  </button>
);

/* ─── Main component ──────────────────────────────────────── */
export default function AnalyticsPage() {
  const [range, setRange]       = useState("weekly");
  const [chartType, setChartType] = useState("area");
  const [animated, setAnimated] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setAnimated(true), 100);
    return () => clearTimeout(t);
  }, []);

  const data = range === "weekly" ? WEEKLY_DATA : MONTHLY_DATA;

  const card = {
    background: "rgba(15,23,42,0.6)",
    border: "1px solid rgba(255,255,255,0.06)",
    borderRadius: 20,
    padding: "20px 24px",
    backdropFilter: "blur(12px)",
  };

  /* ── Render the right chart type ── */
  const renderActivityChart = () => {
    const commonProps = {
      data,
      margin: { top: 5, right: 10, left: -20, bottom: 0 },
    };
    const xAxis = <XAxis dataKey="day" tick={{ fill: "#475569", fontSize: 11 }} axisLine={false} tickLine={false} />;
    const yAxis = <YAxis tick={{ fill: "#475569", fontSize: 11 }} axisLine={false} tickLine={false} />;
    const grid  = <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" vertical={false} />;
    const tip   = <Tooltip content={<CustomTooltip />} />;

    if (chartType === "area") return (
      <AreaChart {...commonProps}>
        <defs>
          <linearGradient id="gSessions" x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%"  stopColor="#a3e635" stopOpacity={0.3} />
            <stop offset="95%" stopColor="#a3e635" stopOpacity={0}   />
          </linearGradient>
          <linearGradient id="gAdvice" x1="0" y1="0" x2="0" y2="1">
            <stop offset="5%"  stopColor="#60a5fa" stopOpacity={0.3} />
            <stop offset="95%" stopColor="#60a5fa" stopOpacity={0}   />
          </linearGradient>
        </defs>
        {grid}{xAxis}{yAxis}{tip}
        <Area type="monotone" dataKey="sessions" name="Sessions" stroke="#a3e635" strokeWidth={2} fill="url(#gSessions)" dot={false} activeDot={{ r: 5, fill: "#a3e635" }} />
        <Area type="monotone" dataKey="advice"   name="Advice"   stroke="#60a5fa" strokeWidth={2} fill="url(#gAdvice)"   dot={false} activeDot={{ r: 5, fill: "#60a5fa" }} />
      </AreaChart>
    );

    if (chartType === "bar") return (
      <BarChart {...commonProps} barGap={4}>
        {grid}{xAxis}{yAxis}{tip}
        <Bar dataKey="sessions" name="Sessions" fill="rgba(163,230,53,0.7)" radius={[4, 4, 0, 0]} />
        <Bar dataKey="advice"   name="Advice"   fill="rgba(96,165,250,0.7)"  radius={[4, 4, 0, 0]} />
      </BarChart>
    );

    if (chartType === "line") return (
      <LineChart {...commonProps}>
        {grid}{xAxis}{yAxis}{tip}
        <Line type="monotone" dataKey="sessions" name="Sessions" stroke="#a3e635" strokeWidth={2} dot={{ fill: "#a3e635", r: 3 }} activeDot={{ r: 6 }} />
        <Line type="monotone" dataKey="advice"   name="Advice"   stroke="#60a5fa" strokeWidth={2} dot={{ fill: "#60a5fa", r: 3 }} activeDot={{ r: 6 }} />
      </LineChart>
    );
  };

  return (
    <AppLayout title="Analytics" subtitle="Track your startup progress and AI usage metrics.">
      <div style={{ maxWidth: 860, display: "flex", flexDirection: "column", gap: 20 }}>

        {/* ── Metric cards ── */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: 14 }}>
          {METRICS.map((m, i) => (
            <div
              key={m.label}
              style={{
                ...card,
                background: m.bg,
                border: `1px solid ${m.border}`,
                opacity: animated ? 1 : 0,
                transform: animated ? "translateY(0)" : "translateY(12px)",
                transition: `opacity 0.4s ${i * 0.08}s, transform 0.4s ${i * 0.08}s`,
              }}
            >
              <p style={{ fontSize: 11, color: "#64748b", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 8 }}>
                {m.label}
              </p>
              <p style={{ fontSize: 28, fontWeight: 800, color: m.color, lineHeight: 1 }}>{m.value}</p>
              <p style={{ fontSize: 11, color: "#475569", marginTop: 6 }}>{m.delta}</p>
            </div>
          ))}
        </div>

        {/* ── Activity chart ── */}
        <div
          style={{
            ...card,
            opacity: animated ? 1 : 0,
            transform: animated ? "translateY(0)" : "translateY(12px)",
            transition: "opacity 0.4s 0.3s, transform 0.4s 0.3s",
          }}
        >
          {/* Header */}
          <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 20, flexWrap: "wrap", gap: 10 }}>
            <div>
              <h3 style={{ color: "#f1f5f9", fontWeight: 700, fontSize: 14, margin: 0 }}>AI Activity</h3>
              <p style={{ color: "#475569", fontSize: 12, marginTop: 3 }}>Sessions and advice actions over time</p>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              {/* Range tabs */}
              <div style={{ display: "flex", gap: 4, background: "rgba(255,255,255,0.03)", borderRadius: 10, padding: 3 }}>
                <Tab active={range === "weekly"}  onClick={() => setRange("weekly")}>Week</Tab>
                <Tab active={range === "monthly"} onClick={() => setRange("monthly")}>Month</Tab>
              </div>
              {/* Chart type */}
              <div style={{ display: "flex", gap: 3 }}>
                <ChartBtn active={chartType === "area"} onClick={() => setChartType("area")}>Area</ChartBtn>
                <ChartBtn active={chartType === "bar"}  onClick={() => setChartType("bar")}>Bar</ChartBtn>
                <ChartBtn active={chartType === "line"} onClick={() => setChartType("line")}>Line</ChartBtn>
              </div>
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: "flex", gap: 16, marginBottom: 16 }}>
            {[["#a3e635", "Sessions"], ["#60a5fa", "Advice"]].map(([color, label]) => (
              <div key={label} style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <div style={{ width: 8, height: 8, borderRadius: "50%", background: color }} />
                <span style={{ fontSize: 11, color: "#64748b" }}>{label}</span>
              </div>
            ))}
          </div>

          <ResponsiveContainer width="100%" height={200}>
            {renderActivityChart()}
          </ResponsiveContainer>
        </div>

        {/* ── Score trend + Radial progress ── */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>

          {/* Score trend line */}
          <div
            style={{
              ...card,
              opacity: animated ? 1 : 0,
              transform: animated ? "translateY(0)" : "translateY(12px)",
              transition: "opacity 0.4s 0.4s, transform 0.4s 0.4s",
            }}
          >
            <h3 style={{ color: "#f1f5f9", fontWeight: 700, fontSize: 14, margin: "0 0 4px 0" }}>Profile Score</h3>
            <p style={{ color: "#475569", fontSize: 12, marginBottom: 16 }}>Completeness over time</p>
            <ResponsiveContainer width="100%" height={140}>
              <AreaChart data={WEEKLY_DATA} margin={{ top: 5, right: 10, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="gScore" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%"  stopColor="#22d3ee" stopOpacity={0.4} />
                    <stop offset="95%" stopColor="#22d3ee" stopOpacity={0}   />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" vertical={false} />
                <XAxis dataKey="day" tick={{ fill: "#475569", fontSize: 10 }} axisLine={false} tickLine={false} />
                <YAxis tick={{ fill: "#475569", fontSize: 10 }} axisLine={false} tickLine={false} domain={[50, 100]} />
                <Tooltip content={<CustomTooltip />} />
                <Area type="monotone" dataKey="score" name="Score" stroke="#22d3ee" strokeWidth={2} fill="url(#gScore)" dot={false} activeDot={{ r: 5, fill: "#22d3ee" }} />
              </AreaChart>
            </ResponsiveContainer>
          </div>

          {/* Radial progress */}
          <div
            style={{
              ...card,
              opacity: animated ? 1 : 0,
              transform: animated ? "translateY(0)" : "translateY(12px)",
              transition: "opacity 0.4s 0.5s, transform 0.4s 0.5s",
            }}
          >
            <h3 style={{ color: "#f1f5f9", fontWeight: 700, fontSize: 14, margin: "0 0 4px 0" }}>Startup Progress</h3>
            <p style={{ color: "#475569", fontSize: 12, marginBottom: 8 }}>Key milestones completion</p>
            <ResponsiveContainer width="100%" height={160}>
              <RadialBarChart
                cx="50%" cy="50%"
                innerRadius="20%" outerRadius="90%"
                data={PROGRESS_DATA}
                startAngle={180} endAngle={-180}
              >
                <RadialBar minAngle={15} dataKey="value" background={{ fill: "rgba(255,255,255,0.03)" }} cornerRadius={4} />
                <Tooltip
                  content={({ active, payload }) =>
                    active && payload?.length ? (
                      <div style={{ background: "#0f172a", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 10, padding: "8px 12px", fontSize: 12 }}>
                        <p style={{ color: payload[0].payload.fill, fontWeight: 700 }}>{payload[0].payload.name}</p>
                        <p style={{ color: "#94a3b8" }}>{payload[0].value}%</p>
                      </div>
                    ) : null
                  }
                />
              </RadialBarChart>
            </ResponsiveContainer>
            {/* Legend */}
            <div style={{ display: "flex", flexDirection: "column", gap: 4, marginTop: 4 }}>
              {PROGRESS_DATA.map((p) => (
                <div key={p.name} style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    <div style={{ width: 6, height: 6, borderRadius: "50%", background: p.fill }} />
                    <span style={{ fontSize: 11, color: "#64748b" }}>{p.name}</span>
                  </div>
                  <span style={{ fontSize: 11, color: p.fill, fontWeight: 700 }}>{p.value}%</span>
                </div>
              ))}
            </div>
          </div>

        </div>

        <p style={{ textAlign: "center", color: "#334155", fontSize: 11, fontFamily: "monospace", paddingBottom: 8 }}>
          Analytics update as you use the AI advisor · Connect real data via the API
        </p>

      </div>
    </AppLayout>
  );
}
